promptTemplate:
MEETING TITLE: {{meeting-title}}

ATTENDEES:
{{attendees}}

ADDITIONAL CONTEXT:
{{context}}

The meeting transcript has been attached as a file. Use it as the primary source for all summaries.

outputFunction:
function fmt(data) {
    if (typeof data !== 'string' || !data.trim()) return '**Meeting Summary**

*No output received.*';
    var text = data.trim();
    var line = '─'.repeat(50);
    var md = '📝 **MEETING SUMMARY**  
' + line + '

';
    md += text + '

';
    md += line + '
';
    md += '⚠️ *AI-generated summary. Review for accuracy before distributing.*  
';
    return md;
}
try{return fmt(data);}catch(e){return'⚠️ Error: '+e.message+'

'+(typeof data==='string'?data:String(data));}
